import { describe, it, expect, vi, beforeEach } from 'vitest';
import { AppController } from './app.controller';

// El controller es delegación pura sobre AppService: cada endpoint reenvía sus
// argumentos al método de servicio correspondiente (y el usuario actual cuando aplica).
describe('AppController — Caja', () => {
  let service: Record<string, ReturnType<typeof vi.fn>>;
  let controller: AppController;

  beforeEach(() => {
    service = {
      registrarPago: vi.fn().mockResolvedValue({ ok: true }),
      listarTransacciones: vi.fn().mockResolvedValue({ data: [] }),
      abrirTurno: vi.fn().mockResolvedValue({ id: 'turno-1' }),
      obtenerTurnoActivo: vi.fn().mockResolvedValue(null),
      obtenerResumenTurnoActivo: vi.fn().mockResolvedValue({ turno: null }),
      obtenerResumenTurno: vi.fn().mockResolvedValue({ turno: { id: 't-1' } }),
      listarMovimientosTurno: vi.fn().mockResolvedValue({ data: [] }),
      crearMovimiento: vi.fn().mockResolvedValue({ id: 'mov-1' }),
      registrarArqueo: vi.fn().mockResolvedValue({ id: 'arq-1' }),
      cerrarTurno: vi.fn().mockResolvedValue({ turno: { estado: 'CERRADA' } }),
    };
    controller = new AppController(service as any);
  });

  it('healthCheck reporta el servicio', () => {
    expect(controller.healthCheck()).toEqual({ status: 'OK', service: 'Caja' });
  });

  it('registrarPago delega con el usuario actual', async () => {
    const body = { cuentaId: 'c-1', montoRecibido: 50, metodo: 'EFECTIVO' } as any;
    await controller.registrarPago(body, 'u-1');
    expect(service.registrarPago).toHaveBeenCalledWith(body, 'u-1');
  });

  it('P-62: registrarPago acepta token S2S sin email/nombre', async () => {
    const body = { cuentaId: 'c-1', montoRecibido: 50, metodo: 'EFECTIVO' } as any;
    await expect(controller.registrarPago(body, 'svc-caja')).resolves.toEqual({ ok: true });
    expect(service.registrarPago).toHaveBeenCalledWith(body, 'svc-caja');
  });

  it('listarTransacciones delega el query', async () => {
    await controller.listarTransacciones({ limit: 10 } as any);
    expect(service.listarTransacciones).toHaveBeenCalledWith({ limit: 10 });
  });

  it('abrirTurno delega body y usuario', async () => {
    await controller.abrirTurno({ fondoInicial: 100 } as any, 'u-1');
    expect(service.abrirTurno).toHaveBeenCalledWith({ fondoInicial: 100 }, 'u-1');
  });

  it('obtenerTurnoActivo / resumenActivo delegan el usuario', async () => {
    await controller.obtenerTurnoActivo('u-1');
    await controller.obtenerResumenTurnoActivo('u-1');
    expect(service.obtenerTurnoActivo).toHaveBeenCalledWith('u-1');
    expect(service.obtenerResumenTurnoActivo).toHaveBeenCalledWith('u-1');
  });

  it('obtenerResumenTurno / listarMovimientosTurno delegan el id', async () => {
    await controller.obtenerResumenTurno('turno-1');
    await controller.listarMovimientosTurno('turno-1');
    expect(service.obtenerResumenTurno).toHaveBeenCalledWith('turno-1');
    expect(service.listarMovimientosTurno).toHaveBeenCalledWith('turno-1');
  });

  it('crearMovimiento delega id y body', async () => {
    const body = { tipo: 'INGRESO', monto: 10, donde: 'caja' } as any;
    await controller.crearMovimiento('turno-1', body);
    expect(service.crearMovimiento).toHaveBeenCalledWith('turno-1', body);
  });

  it('registrarArqueo delega id, body y usuario', async () => {
    const body = { denominaciones: {} } as any;
    await controller.registrarArqueo('turno-1', body, 'u-1');
    expect(service.registrarArqueo).toHaveBeenCalledWith('turno-1', body, 'u-1');
  });

  it('cerrarTurno delega id, body y usuario', async () => {
    const body = { denominaciones: {} } as any;
    await controller.cerrarTurno('turno-1', body, 'u-1');
    expect(service.cerrarTurno).toHaveBeenCalledWith('turno-1', body, 'u-1');
  });
});

import {
  BadRequestException,
  Injectable,
  Logger,
  NotFoundException,
  ServiceUnavailableException,
} from '@nestjs/common';
import { getOrCreateCounter, getOrCreateHistogram } from '@org/observabilidad';
import { PrismaService } from '../prisma/prisma.service';
import {
  ListarTransaccionesQuery,
  PagoRegistradoPayload,
  RoutingKeys,
  TransaccionDto,
  TransaccionListResponse,
} from '@org/contracts';
import { Prisma } from '../generated/prisma';
import {
  AbrirTurnoCajaCommand,
  CerrarTurnoCajaCommand,
  CrearMovimientoCajaCommand,
  PagarCuentaCajaCommand,
  RegistrarArqueoCajaCommand,
} from './caja.dto';
import { CuentasHttpClient, CuentaRemota } from './cuentas-http.client';

const METODOS = ['EFECTIVO', 'TARJETA', 'YAPE', 'PLIN', 'TRANSFERENCIA'] as const;

@Injectable()
export class AppService {
  private readonly logger = new Logger(AppService.name);
  // Métricas de negocio (plan 5.2): pagos/min y distribución de montos.
  private readonly pagosCounter = getOrCreateCounter(
    'pagos_registrados_total', 'Pagos registrados en caja', ['metodo'],
  );
  private readonly pagoMontoHistogram = getOrCreateHistogram(
    'pago_monto_soles', 'Distribución del monto de los pagos (soles)',
    [10, 25, 50, 100, 200, 500, 1000],
    ['metodo'],
  );
  constructor(
    private readonly prisma: PrismaService,
    private readonly cuentasHttp: CuentasHttpClient,
  ) {}

  private usuario(usuarioId?: string | null) {
    return usuarioId ?? 'sistema';
  }

  private n(value: unknown): number {
    return Number(value ?? 0);
  }

  private money(value: number | string | Prisma.Decimal) {
    return new Prisma.Decimal(value);
  }

  async abrirTurno(command: AbrirTurnoCajaCommand, usuarioId?: string | null) {
    const abierto = await this.prisma.turnoCaja.findFirst({
      where: { estado: 'ABIERTA' },
      orderBy: { abiertoAt: 'desc' },
    });

    if (abierto) return this.mapTurno(abierto);

    const fondoInicial = this.money(command.fondoInicial ?? 0);
    let turno;
    try {
      turno = await this.prisma.$transaction(async (prisma: import('../generated/prisma').Prisma.TransactionClient) => {
        const creado = await prisma.turnoCaja.create({
          data: {
            cajaId: command.cajaId ?? 'T01',
            cajaNombre: command.cajaNombre ?? 'Terminal 01',
            usuarioId: this.usuario(usuarioId),
            cajeroNombre: command.cajeroNombre,
            fondoInicial,
            estado: 'ABIERTA',
          },
        });

        await prisma.movimientoCaja.create({
          data: {
            turnoId: creado.id,
            tipo: 'APERTURA',
            donde: 'Fondo inicial',
            metodo: 'EFECTIVO',
            monto: fondoInicial,
          },
        });

        return creado;
      });
    } catch (error) {
      // T-25: carrera con otra apertura concurrente — el índice único parcial
      // `turnos_caja_un_abierto` rechaza el segundo INSERT con P2002. Devolver el
      // turno ya abierto (misma semántica que "si ya hay uno, devolverlo").
      if (this.isUniqueConstraintViolation(error)) {
        const existente = await this.prisma.turnoCaja.findFirst({
          where: { estado: 'ABIERTA' },
          orderBy: { abiertoAt: 'desc' },
        });
        if (existente) return this.mapTurno(existente);
      }
      throw error;
    }

    this.logger.log(`Turno de caja ${turno.id} abierto`);
    return this.mapTurno(turno);
  }

  private isUniqueConstraintViolation(error: unknown): boolean {
    return typeof error === 'object' && error !== null && (error as { code?: string }).code === 'P2002';
  }

  async obtenerTurnoActivo(_usuarioId?: string | null) {
    const turno = await this.prisma.turnoCaja.findFirst({
      where: { estado: 'ABIERTA' },
      orderBy: { abiertoAt: 'desc' },
    });
    return turno ? this.mapTurno(turno) : null;
  }

  async obtenerResumenTurnoActivo(_usuarioId?: string | null) {
    const turno = await this.prisma.turnoCaja.findFirst({
      where: { estado: 'ABIERTA' },
      orderBy: { abiertoAt: 'desc' },
    });

    if (!turno) {
      return {
        turno: null,
        movimientos: [],
        ventas: [],
        totalVentas: 0,
        totalEgresos: 0,
        totalIngresos: 0,
        propinas: 0,
        porMetodo: this.emptyMetodoTotals(),
        efectivoEsperado: 0,
        comprobantes: 0,
        pendientes: 0,
        arqueo: null,
        cierre: null,
      };
    }

    return this.obtenerResumenTurno(turno.id);
  }

  async obtenerResumenTurno(id: string) {
    const turno = await this.prisma.turnoCaja.findUnique({
      where: { id },
      include: {
        movimientos: { orderBy: { createdAt: 'desc' } },
        arqueos: { orderBy: { createdAt: 'desc' }, take: 1 },
        cierre: true,
      },
    });

    if (!turno) throw new NotFoundException(`Turno ${id} no encontrado`);
    return this.buildResumen(turno);
  }

  async listarMovimientosTurno(id: string) {
    const movimientos = await this.prisma.movimientoCaja.findMany({
      where: { turnoId: id },
      orderBy: { createdAt: 'desc' },
    });
    return { data: movimientos.map((m) => this.mapMovimiento(m)) };
  }

  async crearMovimiento(id: string, command: CrearMovimientoCajaCommand) {
    const turno = await this.prisma.turnoCaja.findUnique({ where: { id } });
    if (!turno) throw new NotFoundException(`Turno ${id} no encontrado`);
    if (turno.estado !== 'ABIERTA') {
      throw new BadRequestException('El turno ya está cerrado.');
    }

    const absMonto = Math.abs(command.monto);
    const monto = command.tipo === 'EGRESO' ? -absMonto : absMonto;
    const movimiento = await this.prisma.movimientoCaja.create({
      data: {
        turnoId: id,
        tipo: command.tipo,
        donde: command.donde,
        metodo: 'EFECTIVO',
        monto: this.money(monto),
        motivo: command.motivo,
      },
    });

    return this.mapMovimiento(movimiento);
  }

  async registrarArqueo(id: string, command: RegistrarArqueoCajaCommand, usuarioId?: string | null) {
    const turno = await this.prisma.turnoCaja.findUnique({
      where: { id },
      include: { movimientos: true },
    });
    if (!turno) throw new NotFoundException(`Turno ${id} no encontrado`);

    const efectivoEsperado = this.computeEfectivoEsperado(turno.movimientos);
    const efectivoContado = this.sumDenominaciones(command.denominaciones);
    const diferencia = efectivoContado.minus(efectivoEsperado);

    const arqueo = await this.prisma.arqueoCaja.create({
      data: {
        turnoId: id,
        denominaciones: command.denominaciones,
        efectivoEsperado,
        efectivoContado,
        diferencia,
        usuarioId: this.usuario(usuarioId),
      },
    });

    return this.mapArqueo(arqueo);
  }

  async cerrarTurno(id: string, command: CerrarTurnoCajaCommand, usuarioId?: string | null) {
    const cierre = await this.prisma.$transaction(async (prisma: import('../generated/prisma').Prisma.TransactionClient) => {
      const turno = await prisma.turnoCaja.findUnique({
        where: { id },
        include: {
          movimientos: { orderBy: { createdAt: 'desc' } },
          arqueos: { orderBy: { createdAt: 'desc' }, take: 1 },
          cierre: true,
        },
      });

      if (!turno) throw new NotFoundException(`Turno ${id} no encontrado`);
      if (turno.estado !== 'ABIERTA') {
        throw new BadRequestException('El turno ya está cerrado.');
      }

      const efectivoEsperado = this.computeEfectivoEsperado(turno.movimientos);
      const efectivoContado = this.sumDenominaciones(command.denominaciones);
      const diferencia = efectivoContado.minus(efectivoEsperado);

      const arqueo = await prisma.arqueoCaja.create({
        data: {
          turnoId: id,
          denominaciones: command.denominaciones,
          efectivoEsperado,
          efectivoContado,
          diferencia,
          usuarioId: this.usuario(usuarioId),
        },
      });

      const resumen = this.buildResumen({
        ...turno,
        arqueos: [arqueo],
        cierre: null,
      });

      const cierreCreado = await prisma.cierreCaja.create({
        data: {
          turnoId: id,
          montoEsperado: efectivoEsperado,
          montoReal: efectivoContado,
          diferencia,
          usuarioId: this.usuario(usuarioId),
          resumen,
        },
      });

      const turnoCerrado = await prisma.turnoCaja.update({
        where: { id },
        data: { estado: 'CERRADA', cerradoAt: new Date() },
      });

      return { turno: turnoCerrado, arqueo, cierre: cierreCreado, resumen };
    });

    this.logger.log(`Turno de caja ${id} cerrado`);
    return {
      turno: this.mapTurno(cierre.turno),
      arqueo: this.mapArqueo(cierre.arqueo),
      cierre: this.mapCierre(cierre.cierre),
      resumen: cierre.resumen,
    };
  }

  async registrarPago(
    command: PagarCuentaCajaCommand,
    usuarioId?: string | null,
  ): Promise<{ message?: string; transaccion: TransaccionDto; ticket?: unknown; turno: unknown }> {
    const turno = await this.prisma.turnoCaja.findFirst({
      where: { estado: 'ABIERTA' },
      orderBy: { abiertoAt: 'desc' },
    });
    if (!turno) {
      throw new BadRequestException('No hay turno de caja abierto.');
    }

    let cuentaRemota: CuentaRemota;
    try {
      cuentaRemota = await this.cuentasHttp.fetchCuenta(command.cuentaId);
    } catch (error: unknown) {
      const axiosError = error as { response?: { status: number }; code?: string };
      if (axiosError.response?.status === 404) {
        throw new NotFoundException(`Cuenta ${command.cuentaId} no encontrada.`);
      }
      throw new ServiceUnavailableException('No se pudo obtener la cuenta. Reintente.');
    }

    const descuento = this.money(command.descuento ?? 0);
    const montoRecibido = this.money(command.montoRecibido);
    const totalConDescuento = Prisma.Decimal.max(
      new Prisma.Decimal(0),
      this.money(cuentaRemota.total).minus(descuento),
    );

    if (!montoRecibido.equals(totalConDescuento)) {
      throw new BadRequestException(
        `El pago debe cubrir el total exacto. Total con descuento: ${totalConDescuento.toNumber()}, recibido: ${montoRecibido.toNumber()}.`,
      );
    }

    const transaccion = await this.prisma.$transaction(async (prisma: import('../generated/prisma').Prisma.TransactionClient) => {
      // classid 1234 compartido entre servicios A PROPOSITO: cada servicio tiene su propia BD (database-per-service), el espacio de locks no se cruza.
      await prisma.$executeRaw`SELECT pg_advisory_xact_lock(1234, ('x' || substr(md5(${command.cuentaId}), 1, 8))::bit(32)::int)`;

      const cuenta = await prisma.cuentaAbierta.upsert({
        where: { cuentaId: command.cuentaId },
        create: {
          cuentaId: cuentaRemota.id,
          mesaId: cuentaRemota.mesaId,
          total: cuentaRemota.total,
          estado: cuentaRemota.estado,
        },
        update: {
          total: cuentaRemota.total,
          estado: cuentaRemota.estado,
          mesaId: cuentaRemota.mesaId,
        },
      });

      if (cuenta.estado !== 'ABIERTA') {
        throw new BadRequestException(`La cuenta ya está ${cuenta.estado.toLowerCase()}.`);
      }

      const pagosPrevios = await prisma.transaccion.aggregate({
        where: { cuentaId: command.cuentaId },
        _sum: { monto: true },
      });
      const montoTotalPagado = this.money(pagosPrevios._sum.monto ?? 0);

      if (montoTotalPagado.greaterThan(0)) {
        throw new BadRequestException('La cuenta ya tiene un pago registrado.');
      }

      const tx = await prisma.transaccion.create({
        data: {
          cuentaId: command.cuentaId,
          turnoId: turno.id,
          mesaId: cuenta.mesaId,
          monto: montoRecibido,
          descuento,
          metodo: command.metodo,
          referencia: command.referencia,
          notas: command.notas,
        },
      });

      await prisma.movimientoCaja.create({
        data: {
          turnoId: turno.id,
          tipo: 'VENTA',
          cuentaId: command.cuentaId,
          transaccionId: tx.id,
          mesaId: cuenta.mesaId,
          donde: command.mesaNumero ? `Mesa ${command.mesaNumero}` : `Mesa ${cuenta.mesaId}`,
          metodo: command.metodo,
          monto: montoRecibido,
          descuento,
          propina: this.money(command.propina ?? 0),
          motivo: command.notas,
        },
      });

      const payload: PagoRegistradoPayload = {
        transaccionId: tx.id,
        cuentaId: command.cuentaId,
        mesaId: cuenta.mesaId,
        monto: montoRecibido.toNumber(),
        metodo: command.metodo,
      };

      await prisma.outboxEvent.create({
        data: {
          routingKey: RoutingKeys.PagoRegistrado,
          payload: JSON.stringify(payload),
          status: 'PENDING',
        },
      });

      return tx;
    });

    let ticket: unknown;
    try {
      const cierre = await this.cuentasHttp.cerrarCuenta(command.cuentaId, descuento.toNumber());
      ticket = cierre?.ticket;
      await this.prisma.cuentaAbierta.update({
        where: { cuentaId: command.cuentaId },
        data: { estado: 'CERRADA', total: totalConDescuento },
      });
    } catch (error) {
      this.logger.warn(`Pago ${transaccion.id} registrado; cierre remoto pendiente: ${(error as Error).message}`);
    }

    const transaccionDto = this.mapTransaccion(transaccion);
    this.pagosCounter.inc({ metodo: command.metodo });
    this.pagoMontoHistogram.observe({ metodo: command.metodo }, montoRecibido.toNumber());
    this.logger.log(`Pago registrado para cuenta ${command.cuentaId}`);
    return {
      message: ticket ? 'Pago registrado, cuenta cerrada y ticket generado' : 'Pago registrado; cierre de cuenta en proceso',
      transaccion: transaccionDto,
      ticket,
      turno: this.mapTurno(turno),
    };
  }

  async listarTransacciones(query: ListarTransaccionesQuery = {}): Promise<TransaccionListResponse> {
    const limit = this.normalizeLimit(query.limit);
    const where: Prisma.TransaccionWhereInput = {
      ...(query.metodo ? { metodo: query.metodo } : {}),
      ...(query.updatedSince
        ? { createdAt: { gte: new Date(query.updatedSince) } }
        : {}),
    };

    const transacciones = await this.prisma.transaccion.findMany({
      where,
      take: limit + 1,
      ...(query.cursor ? { cursor: { id: query.cursor }, skip: 1 } : {}),
      orderBy: [{ createdAt: 'desc' }, { id: 'desc' }],
    });

    const hasMore = transacciones.length > limit;
    const data = transacciones.slice(0, limit);

    return {
      data: data.map((t) => this.mapTransaccion(t)),
      nextCursor: hasMore ? data.at(-1)?.id ?? null : null,
    };
  }

  private normalizeLimit(limit?: number): number {
    const parsed = Number(limit ?? 20);
    if (!Number.isFinite(parsed)) return 20;
    return Math.min(Math.max(Math.trunc(parsed), 1), 100);
  }

  /* eslint-disable @typescript-eslint/no-explicit-any */
  private buildResumen(turno: import('../generated/prisma').TurnoCaja & { movimientos?: import('../generated/prisma').MovimientoCaja[] }) {
    const movimientos = Array.isArray(turno.movimientos) ? turno.movimientos : [];
    const ventas = movimientos.filter((m: import('../generated/prisma').MovimientoCaja) => m.tipo === 'VENTA');
    const ingresos = movimientos.filter((m: import('../generated/prisma').MovimientoCaja) => m.tipo === 'INGRESO');
    const egresos = movimientos.filter((m: import('../generated/prisma').MovimientoCaja) => m.tipo === 'EGRESO');
    const totalVentas = this.sum(ventas.map((m: import('../generated/prisma').MovimientoCaja) => m.monto));
    const totalIngresos = this.sum(ingresos.map((m: import('../generated/prisma').MovimientoCaja) => m.monto));
    const totalEgresos = this.sum(egresos.map((m: import('../generated/prisma').MovimientoCaja) => m.monto));
    const propinas = this.sum(movimientos.map((m: import('../generated/prisma').MovimientoCaja) => m.propina ?? 0));
    const porMetodo = this.emptyMetodoTotals();

    ventas.forEach((m: import('../generated/prisma').MovimientoCaja) => {
      if (m.metodo in porMetodo) porMetodo[m.metodo] += this.n(m.monto);
    });

    return {
      turno: this.mapTurno(turno),
      movimientos: movimientos.map((m: import('../generated/prisma').MovimientoCaja) => this.mapMovimiento(m)),
      ventas: ventas.map((m: import('../generated/prisma').MovimientoCaja) => this.mapMovimiento(m)),
      totalVentas: totalVentas.toNumber(),
      totalEgresos: totalEgresos.toNumber(),
      totalIngresos: totalIngresos.toNumber(),
      propinas: propinas.toNumber(),
      porMetodo,
      efectivoEsperado: this.computeEfectivoEsperado(movimientos).toNumber(),
      comprobantes: ventas.length,
      pendientes: 0,
      arqueo: turno.arqueos?.[0] ? this.mapArqueo(turno.arqueos[0]) : null,
      cierre: turno.cierre ? this.mapCierre(turno.cierre) : null,
    };
  }

  private computeEfectivoEsperado(movimientos: import('../generated/prisma').MovimientoCaja[]) {
    return this.sum(
      movimientos
        .filter((m) => m.metodo === 'EFECTIVO')
        .map((m) => this.money(m.monto).plus(this.money(m.propina ?? 0))),
    );
  }

  private sum(values: unknown[]) {
    return values.reduce(
      (acc: Prisma.Decimal, value) => acc.plus(this.money(value as any)),
      new Prisma.Decimal(0),
    );
  }

  private sumDenominaciones(denominaciones: Record<string, number>) {
    return Object.entries(denominaciones).reduce((acc, [denom, count]) => {
      const d = Number(denom);
      const q = Number(count);
      if (!Number.isFinite(d) || !Number.isFinite(q) || q < 0) return acc;
      return acc.plus(new Prisma.Decimal(d).times(q));
    }, new Prisma.Decimal(0));
  }

  private emptyMetodoTotals() {
    return METODOS.reduce((acc, metodo) => {
      acc[metodo] = 0;
      return acc;
    }, {} as Record<string, number>);
  }

  private mapTransaccion(t: import('../generated/prisma').TransaccionCaja): TransaccionDto {
    return {
      id: t.id,
      cuentaId: t.cuentaId,
      monto: this.n(t.monto),
      descuento: this.n(t.descuento),
      metodo: t.metodo,
      referencia: t.referencia || undefined,
      notas: t.notas || undefined,
      createdAt: t.createdAt.toISOString(),
    };
  }

  private mapTurno(t: import('../generated/prisma').TurnoCaja) {
    return {
      id: t.id,
      cajaId: t.cajaId,
      cajaNombre: t.cajaNombre,
      usuarioId: t.usuarioId,
      cajeroNombre: t.cajeroNombre ?? null,
      fondoInicial: this.n(t.fondoInicial),
      estado: t.estado,
      abiertoAt: t.abiertoAt.toISOString(),
      cerradoAt: t.cerradoAt?.toISOString() ?? null,
      createdAt: t.createdAt.toISOString(),
      updatedAt: t.updatedAt.toISOString(),
    };
  }

  private mapMovimiento(m: import('../generated/prisma').MovimientoCaja) {
    return {
      id: m.id,
      turnoId: m.turnoId,
      tipo: m.tipo,
      cuentaId: m.cuentaId ?? null,
      transaccionId: m.transaccionId ?? null,
      mesaId: m.mesaId ?? null,
      donde: m.donde,
      metodo: m.metodo,
      monto: this.n(m.monto),
      descuento: this.n(m.descuento),
      propina: this.n(m.propina),
      motivo: m.motivo ?? null,
      createdAt: m.createdAt.toISOString(),
    };
  }

  private mapArqueo(a: import('../generated/prisma').ArqueoCaja) {
    return {
      id: a.id,
      turnoId: a.turnoId,
      denominaciones: a.denominaciones,
      efectivoEsperado: this.n(a.efectivoEsperado),
      efectivoContado: this.n(a.efectivoContado),
      diferencia: this.n(a.diferencia),
      usuarioId: a.usuarioId,
      createdAt: a.createdAt.toISOString(),
    };
  }

  private mapCierre(c: import('../generated/prisma').CierreCaja) {
    return {
      id: c.id,
      turnoId: c.turnoId ?? null,
      montoEsperado: this.n(c.montoEsperado),
      montoReal: this.n(c.montoReal),
      diferencia: this.n(c.diferencia),
      usuarioId: c.usuarioId,
      resumen: c.resumen ?? null,
      createdAt: c.createdAt.toISOString(),
    };
  }
  /* eslint-enable @typescript-eslint/no-explicit-any */
}

import { describe, it, expect, vi, beforeEach } from 'vitest';
import axios from 'axios';

// Mocks de borde (igual que app.service.spec.ts): axios para la cuenta remota y
// el decorador de circuit-breaker como passthrough.
vi.mock('axios', () => ({
  default: { get: vi.fn(), post: vi.fn() },
}));

vi.mock('@org/resiliencia', async () => {
  const actual = await vi.importActual('@org/resiliencia');
  return {
    ...actual,
    CircuitBreakerOptions: () => (_t: any, _k: string, d: PropertyDescriptor) => d,
  };
});

import { AppService } from './app.service';
import { CuentasHttpClient } from './cuentas-http.client';

const baseTurno = {
  id: 'turno-001',
  cajaId: 'T01',
  cajaNombre: 'Terminal 01',
  usuarioId: 'u-001',
  cajeroNombre: 'Caja',
  fondoInicial: 300,
  estado: 'ABIERTA' as string,
  abiertoAt: new Date('2026-06-10T08:00:00Z'),
  cerradoAt: null as Date | null,
  createdAt: new Date('2026-06-10T08:00:00Z'),
  updatedAt: new Date('2026-06-10T08:00:00Z'),
};

function mov(overrides: Record<string, any> = {}) {
  return {
    id: 'mov-1',
    turnoId: 'turno-001',
    tipo: 'VENTA',
    cuentaId: null,
    transaccionId: null,
    mesaId: null,
    donde: 'Mesa 1',
    metodo: 'EFECTIVO',
    monto: 50,
    descuento: 0,
    propina: 0,
    motivo: null,
    createdAt: new Date('2026-06-10T09:00:00Z'),
    ...overrides,
  };
}

function createMockPrisma(overrides: Record<string, any> = {}) {
  const prisma: any = {
    $connect: async () => {},
    $disconnect: async () => {},
    checkAndRecordIdempotencyKey: async () => true,
    turnoCaja: { findFirst: vi.fn(), findUnique: vi.fn(), create: vi.fn(), update: vi.fn() },
    movimientoCaja: { create: vi.fn(), findMany: vi.fn() },
    arqueoCaja: { create: vi.fn() },
    cierreCaja: { create: vi.fn() },
    transaccion: { create: vi.fn(), findMany: vi.fn(), aggregate: vi.fn() },
    cuentaAbierta: { findUnique: vi.fn(), upsert: vi.fn(), update: vi.fn() },
    outboxEvent: { create: vi.fn() },
    $executeRaw: vi.fn(),
    ...overrides,
  };
  prisma.$transaction = vi.fn(async (cb: any) => cb(prisma));
  return prisma;
}

describe('AppService — Caja (turnos, movimientos, arqueo, cierre)', () => {
  let service: AppService;
  let prisma: ReturnType<typeof createMockPrisma>;

  beforeEach(() => {
    vi.clearAllMocks();
    prisma = createMockPrisma();
    process.env['CUENTAS_SERVICE_URL'] = 'http://localhost:3005/api';
    service = new AppService(
      prisma as any,
      new CuentasHttpClient({ generateServiceToken: vi.fn().mockReturnValue('tok') } as any),
    );
  });

  describe('obtenerTurnoActivo', () => {
    it('devuelve null cuando no hay turno abierto', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue(null);
      expect(await service.obtenerTurnoActivo('u-001')).toBeNull();
    });

    it('mapea el turno abierto cuando existe', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue({ ...baseTurno });
      const turno = await service.obtenerTurnoActivo('u-001');
      expect(turno?.id).toBe('turno-001');
      expect(turno?.estado).toBe('ABIERTA');
    });
  });

  describe('obtenerResumenTurnoActivo', () => {
    it('devuelve un resumen vacío si no hay turno', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue(null);
      const resumen = await service.obtenerResumenTurnoActivo('u-001');
      expect(resumen.turno).toBeNull();
      expect(resumen.totalVentas).toBe(0);
      expect(resumen.porMetodo).toMatchObject({ EFECTIVO: 0, TARJETA: 0 });
    });

    it('delega en obtenerResumenTurno cuando hay turno', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue({ ...baseTurno });
      prisma.turnoCaja.findUnique.mockResolvedValue({
        ...baseTurno,
        movimientos: [mov({ tipo: 'VENTA', metodo: 'EFECTIVO', monto: 50 })],
        arqueos: [],
        cierre: null,
      });
      const resumen = await service.obtenerResumenTurnoActivo('u-001');
      expect(resumen.turno?.id).toBe('turno-001');
      expect(resumen.totalVentas).toBe(50);
    });
  });

  describe('obtenerResumenTurno', () => {
    it('lanza NotFound si el turno no existe', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue(null);
      await expect(service.obtenerResumenTurno('x')).rejects.toThrow('no encontrado');
    });

    it('agrega ventas, ingresos, egresos, propinas y efectivo esperado', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue({
        ...baseTurno,
        movimientos: [
          mov({ tipo: 'APERTURA', metodo: 'EFECTIVO', monto: 300, donde: 'Fondo inicial' }),
          mov({ tipo: 'VENTA', metodo: 'EFECTIVO', monto: 50, propina: 5 }),
          mov({ tipo: 'VENTA', metodo: 'TARJETA', monto: 80 }),
          mov({ tipo: 'INGRESO', metodo: 'EFECTIVO', monto: 20 }),
          mov({ tipo: 'EGRESO', metodo: 'EFECTIVO', monto: -10 }),
        ],
        arqueos: [],
        cierre: null,
      });

      const resumen = await service.obtenerResumenTurno('turno-001');

      expect(resumen.totalVentas).toBe(130); // 50 + 80
      expect(resumen.totalIngresos).toBe(20);
      expect(resumen.totalEgresos).toBe(-10);
      expect(resumen.propinas).toBe(5);
      expect(resumen.porMetodo.EFECTIVO).toBe(50);
      expect(resumen.porMetodo.TARJETA).toBe(80);
      expect(resumen.comprobantes).toBe(2);
      // Efectivo esperado: aperturas/ventas/ingresos/egresos EFECTIVO + propinas EFECTIVO
      expect(resumen.efectivoEsperado).toBe(365); // 300 + 50 + 5 + 20 - 10
    });
  });

  describe('listarMovimientosTurno', () => {
    it('mapea los movimientos del turno', async () => {
      prisma.movimientoCaja.findMany.mockResolvedValue([mov({ id: 'm-1' }), mov({ id: 'm-2', tipo: 'EGRESO', monto: -10 })]);
      const res = await service.listarMovimientosTurno('turno-001');
      expect(res.data).toHaveLength(2);
      expect(res.data[1].monto).toBe(-10);
    });
  });

  describe('crearMovimiento', () => {
    it('lanza NotFound si el turno no existe', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue(null);
      await expect(service.crearMovimiento('x', { tipo: 'INGRESO', monto: 10, donde: 'caja' } as any)).rejects.toThrow('no encontrado');
    });

    it('rechaza movimientos sobre un turno cerrado', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue({ ...baseTurno, estado: 'CERRADA' });
      await expect(service.crearMovimiento('turno-001', { tipo: 'INGRESO', monto: 10, donde: 'caja' } as any)).rejects.toThrow('cerrado');
    });

    it('un EGRESO se persiste con monto negativo', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue({ ...baseTurno });
      prisma.movimientoCaja.create.mockResolvedValue(mov({ tipo: 'EGRESO', monto: -25 }));
      const res = await service.crearMovimiento('turno-001', { tipo: 'EGRESO', monto: 25, donde: 'compra' } as any);
      expect(res.monto).toBe(-25);
      expect(prisma.movimientoCaja.create).toHaveBeenCalledWith(
        expect.objectContaining({ data: expect.objectContaining({ tipo: 'EGRESO' }) }),
      );
    });

    it('un INGRESO se persiste con monto positivo', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue({ ...baseTurno });
      prisma.movimientoCaja.create.mockResolvedValue(mov({ tipo: 'INGRESO', monto: 40 }));
      const res = await service.crearMovimiento('turno-001', { tipo: 'INGRESO', monto: 40, donde: 'extra' } as any);
      expect(res.monto).toBe(40);
    });
  });

  describe('registrarArqueo', () => {
    it('lanza NotFound si el turno no existe', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue(null);
      await expect(service.registrarArqueo('x', { denominaciones: {} } as any)).rejects.toThrow('no encontrado');
    });

    it('calcula la diferencia entre lo contado y lo esperado', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue({
        ...baseTurno,
        movimientos: [mov({ tipo: 'APERTURA', metodo: 'EFECTIVO', monto: 100 })],
      });
      prisma.arqueoCaja.create.mockImplementation(async ({ data }: any) => ({
        id: 'arq-1', createdAt: new Date('2026-06-10T10:00:00Z'), ...data,
      }));

      const arqueo = await service.registrarArqueo('turno-001', { denominaciones: { '100': 1, '20': 1 } } as any, 'u-001');

      expect(arqueo.efectivoEsperado).toBe(100);
      expect(arqueo.efectivoContado).toBe(120);
      expect(arqueo.diferencia).toBe(20);
    });
  });

  describe('cerrarTurno', () => {
    it('lanza NotFound si el turno no existe', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue(null);
      await expect(service.cerrarTurno('x', { denominaciones: {} } as any)).rejects.toThrow('no encontrado');
    });

    it('rechaza cerrar un turno ya cerrado', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue({ ...baseTurno, estado: 'CERRADA', movimientos: [], arqueos: [], cierre: null });
      await expect(service.cerrarTurno('turno-001', { denominaciones: {} } as any)).rejects.toThrow('ya está cerrado');
    });

    it('cierra el turno, genera arqueo y cierre con la diferencia', async () => {
      prisma.turnoCaja.findUnique.mockResolvedValue({
        ...baseTurno,
        movimientos: [mov({ tipo: 'APERTURA', metodo: 'EFECTIVO', monto: 200 })],
        arqueos: [],
        cierre: null,
      });
      prisma.arqueoCaja.create.mockImplementation(async ({ data }: any) => ({ id: 'arq-1', createdAt: new Date('2026-06-10T10:00:00Z'), ...data }));
      prisma.cierreCaja.create.mockImplementation(async ({ data }: any) => ({ id: 'cie-1', createdAt: new Date('2026-06-10T10:00:00Z'), ...data }));
      prisma.turnoCaja.update.mockResolvedValue({ ...baseTurno, estado: 'CERRADA', cerradoAt: new Date('2026-06-10T10:00:00Z') });

      const res = await service.cerrarTurno('turno-001', { denominaciones: { '200': 1 } } as any, 'u-001');

      expect(res.turno.estado).toBe('CERRADA');
      expect(res.cierre.montoEsperado).toBe(200);
      expect(res.cierre.montoReal).toBe(200);
      expect(res.cierre.diferencia).toBe(0);
      expect(prisma.turnoCaja.update).toHaveBeenCalledWith(
        expect.objectContaining({ data: expect.objectContaining({ estado: 'CERRADA' }) }),
      );
    });
  });

  describe('registrarPago — caminos de error', () => {
    it('rechaza si no hay turno de caja abierto', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue(null);
      await expect(
        service.registrarPago({ cuentaId: 'c-001', montoRecibido: 50, metodo: 'EFECTIVO' } as any),
      ).rejects.toThrow('No hay turno de caja abierto');
    });

    it('traduce un 404 de la cuenta remota a NotFound', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue({ ...baseTurno });
      vi.mocked(axios.get).mockRejectedValue({ response: { status: 404 } });
      await expect(
        service.registrarPago({ cuentaId: 'c-404', montoRecibido: 50, metodo: 'EFECTIVO' } as any),
      ).rejects.toThrow('no encontrada');
    });

    it('traduce un fallo de red en ServiceUnavailable', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue({ ...baseTurno });
      vi.mocked(axios.get).mockRejectedValue({ code: 'ECONNREFUSED' });
      await expect(
        service.registrarPago({ cuentaId: 'c-001', montoRecibido: 50, metodo: 'EFECTIVO' } as any),
      ).rejects.toThrow('No se pudo obtener la cuenta');
    });

    it('rechaza un segundo pago sobre una cuenta que ya pagó (idempotencia de negocio)', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue({ ...baseTurno });
      vi.mocked(axios.get).mockResolvedValue({ data: { id: 'c-001', mesaId: 'm-001', total: 50, estado: 'ABIERTA' } });
      prisma.cuentaAbierta.upsert.mockResolvedValue({ cuentaId: 'c-001', mesaId: 'm-001', total: 50, estado: 'ABIERTA' });
      prisma.transaccion.aggregate.mockResolvedValue({ _sum: { monto: 50 } });

      await expect(
        service.registrarPago({ cuentaId: 'c-001', montoRecibido: 50, metodo: 'EFECTIVO' } as any),
      ).rejects.toThrow('ya tiene un pago registrado');
    });

    it('rechaza el pago si la cuenta ya no está ABIERTA', async () => {
      prisma.turnoCaja.findFirst.mockResolvedValue({ ...baseTurno });
      vi.mocked(axios.get).mockResolvedValue({ data: { id: 'c-001', mesaId: 'm-001', total: 50, estado: 'CERRADA' } });
      prisma.cuentaAbierta.upsert.mockResolvedValue({ cuentaId: 'c-001', mesaId: 'm-001', total: 50, estado: 'CERRADA' });

      await expect(
        service.registrarPago({ cuentaId: 'c-001', montoRecibido: 50, metodo: 'EFECTIVO' } as any),
      ).rejects.toThrow('ya está cerrada');
    });
  });
});
